import android.app.Activity;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.util.Log;
import android.widget.TextView;

public class ShareActivity extends Activity {

    private static final String TAG = "ShareActivity";

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_share);

        Intent intent = getIntent();
        if (intent.getAction().equals(Intent.ACTION_SEND)) {
            handleShareIntent(intent);
        } else if (intent.getAction().equals(Intent.ACTION_VIEW)) {
            handleViewIntent(intent);
        }
    }

    private void handleShareIntent(Intent intent) {
        String type = intent.getType();

        if (type != null && type.startsWith("image/")) {
            Uri uri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
            Log.d(TAG, "Received image: " + uri.toString());
            displayImage(uri);
        } else if (type.equals("text/plain")) {
            String text = intent.getStringExtra(Intent.EXTRA_TEXT);
            Log.d(TAG, "Received text: " + text);
            displayText(text);
        }
    }

    private void handleViewIntent(Intent intent) {
        Uri uri = intent.getData();
        Log.d(TAG, "Received URI: " + uri.toString());
        displayUri(uri);
    }

    private void displayImage(Uri uri) {
        // Code to display the image
        TextView textView = findViewById(R.id.image_text_view);
        textView.setText("Shared Image");
        // Load the image from the URI
    }

    private void displayText(String text) {
        // Code to display the text
        TextView textView = findViewById(R.id.text_text_view);
        textView.setText(text);
    }

    private void displayUri(Uri uri) {
        // Code to display the URI
        TextView textView = findViewById(R.id.uri_text_view);
        textView.setText(uri.toString());
    }
}